import{_ as t,c as a,o as s,aN as e}from"./chunks/framework.DXgs1r1w.js";const m=JSON.parse('{"title":"AI 核心概念大串联","description":"","frontmatter":{"date":"2026-07-16T16:39:47.000Z","title":"AI 核心概念大串联","permalink":"/pages/767a9c","categories":["AI"]},"headers":[],"relativePath":"AI/01.核心概念.md","filePath":"AI/01.核心概念.md","lastUpdated":1784195928000}'),l={name:"AI/01.核心概念.md"};function o(r,n,i,p,d,u){return s(),a("div",null,[...n[0]||(n[0]=[e(`<h1 id="ai-核心概念大串联" tabindex="-1">AI 核心概念大串联 <a class="header-anchor" href="#ai-核心概念大串联" aria-label="Permalink to &quot;AI 核心概念大串联&quot;">​</a></h1><h2 id="一、整体关系图-先有个全局视角" tabindex="-1">一、整体关系图（先有个全局视角） <a class="header-anchor" href="#一、整体关系图-先有个全局视角" aria-label="Permalink to &quot;一、整体关系图（先有个全局视角）&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌──────────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  LLM（大语言模型）                                                 │</span></span>
<span class="line"><span>│  模型本身，负责&quot;理解+生成&quot;                                          │</span></span>
<span class="line"><span>│   ▲  输入/输出都以 Token 为单位                                     │</span></span>
<span class="line"><span>│   │                                                                │</span></span>
<span class="line"><span>│   │   ┌─────────────── Context（上下文）──────────────────┐        │</span></span>
<span class="line"><span>│   │   │  = System Prompt + User Prompt + 历史 + Tool 结果   │        │</span></span>
<span class="line"><span>│   │   │  受 Context Window（上下文窗口）容量限制            │        │</span></span>
<span class="line"><span>│   │   └────────────────────────────────────────────────────┘       │</span></span>
<span class="line"><span>│   │                                                                │</span></span>
<span class="line"><span>│   ├── Prompt ──┬── System Prompt（设定角色/规则）                  │</span></span>
<span class="line"><span>│   │            └── User Prompt（用户实际输入）                     │</span></span>
<span class="line"><span>│   │                                                                │</span></span>
<span class="line"><span>│   ├── Tool（工具调用）── 通过 MCP 协议连接外部能力                  │</span></span>
<span class="line"><span>│   │                                                                │</span></span>
<span class="line"><span>│   └── Agent（智能体）── 编排 LLM + Prompt + Tool，自主完成任务       │</span></span>
<span class="line"><span>│        └── Agent Skill（技能）── 预置的专用能力/工作流              │</span></span>
<span class="line"><span>└──────────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><p>一句话：<strong>LLM 是引擎，Token 是燃料单位，Context 是它每次&quot;看&quot;到的全部信息（受 Context Window 限制），Prompt 是给它的指令，Tool/MCP 给它手脚，Agent 把这一切编排起来自动干活，Agent Skill 是现成的&quot;专家技能包&quot;。</strong></p><hr><h2 id="二、逐概念拆解" tabindex="-1">二、逐概念拆解 <a class="header-anchor" href="#二、逐概念拆解" aria-label="Permalink to &quot;二、逐概念拆解&quot;">​</a></h2><h3 id="_1-llm-large-language-model-大语言模型" tabindex="-1">1. LLM（Large Language Model，大语言模型） <a class="header-anchor" href="#_1-llm-large-language-model-大语言模型" aria-label="Permalink to &quot;1. LLM（Large Language Model，大语言模型）&quot;">​</a></h3><ul><li>用海量文本训练出来的深度学习模型（如 GPT、Claude、通义、文心等），本质是<strong>预测下一个 Token 的概率机器</strong>。</li><li>能力：文本生成、问答、翻译、代码编写、推理等。</li><li>它本身<strong>没有记忆、没有联网、没有手</strong>（不能操作文件/调 API），所有&quot;超能力&quot;都靠下面这些概念补齐。</li></ul><h3 id="_2-token-词元" tabindex="-1">2. Token（词元） <a class="header-anchor" href="#_2-token-词元" aria-label="Permalink to &quot;2. Token（词元）&quot;">​</a></h3><ul><li>模型读写文本的<strong>最小单位</strong>，不等同于&quot;字&quot;或&quot;词&quot;。英文约 1 Token ≈ 4 字符；中文通常<strong>每 1~2 个汉字 ≈ 1 个 Token</strong>（取决于分词器，常见中文大模型约 1 字 ≈ 1 Token，罕见字/组合字可能更多）。</li><li>计费、限速、上下文长度<strong>都以 Token 计</strong>（如 GPT-4 按输入/输出 Token 分别计费）。</li><li>模型输入和输出都是 Token 序列，生成是<strong>逐 Token 自回归</strong>进行的。</li></ul><h3 id="_3-context-上下文" tabindex="-1">3. Context（上下文） <a class="header-anchor" href="#_3-context-上下文" aria-label="Permalink to &quot;3. Context（上下文）&quot;">​</a></h3><ul><li>指模型<strong>本次推理时所能看到的全部文本</strong>，包括： <ul><li><code>System Prompt</code>（系统指令）</li><li><code>User Prompt</code>（用户输入）</li><li><strong>历史对话</strong>（多轮对话的上下文）</li><li><strong>Tool 调用结果</strong>（工具返回的内容）</li></ul></li><li>模型每次回答都只基于&quot;当前 Context&quot;，它<strong>不记得</strong>窗口之外的对话（这就是为什么长对话需要把历史重新拼进 Context）。</li></ul><h3 id="_4-context-window-上下文窗口" tabindex="-1">4. Context Window（上下文窗口） <a class="header-anchor" href="#_4-context-window-上下文窗口" aria-label="Permalink to &quot;4. Context Window（上下文窗口）&quot;">​</a></h3><ul><li>模型<strong>单次可纳入的最大 Token 总量</strong>（输入 + 已生成的输出都计入窗口）。例如 8K / 32K / 128K / 200K。注意：窗口限制的是&quot;总上下文大小&quot;，而模型<strong>单次生成的输出长度</strong>另有独立的 <code>max_tokens</code> 上限，二者不是互不干扰的两个配额池。</li><li>超出窗口的内容会被<strong>截断或遗忘</strong>，是长文档、长对话的核心瓶颈。</li><li>应对手段：摘要压缩历史、RAG 检索注入、分块处理、长上下文模型。</li></ul><h3 id="_5-prompt-提示词" tabindex="-1">5. Prompt（提示词） <a class="header-anchor" href="#_5-prompt-提示词" aria-label="Permalink to &quot;5. Prompt（提示词）&quot;">​</a></h3><ul><li>给模型的&quot;输入指令/问题&quot;，是驱动模型行为的关键。提示工程（Prompt Engineering）旨在写出更清晰、更有效的指令。</li><li>分为两类：</li></ul><h4 id="_5-1-system-prompt-系统提示" tabindex="-1">5.1 System Prompt（系统提示） <a class="header-anchor" href="#_5-1-system-prompt-系统提示" aria-label="Permalink to &quot;5.1 System Prompt（系统提示）&quot;">​</a></h4><ul><li>在对话最开始注入的<strong>顶层指令</strong>，用来设定模型角色、语气、规则、约束。</li><li>例：<em>&quot;你是一个严谨的中文技术助手，回答要分点、不啰嗦。&quot;</em></li><li>通常用户不可见，由应用/平台预置，且在多轮对话中保持稳定。</li></ul><h4 id="_5-2-user-prompt-用户提示" tabindex="-1">5.2 User Prompt（用户提示） <a class="header-anchor" href="#_5-2-user-prompt-用户提示" aria-label="Permalink to &quot;5.2 User Prompt（用户提示）&quot;">​</a></h4><ul><li>用户<strong>每轮实际输入</strong>的问题或指令。</li><li>与 System Prompt、历史一起构成 Context 交给模型。</li></ul><blockquote><p>关系：<code>Prompt = System Prompt + User Prompt (+ 历史)</code>，是 Context 的主要组成部分。</p></blockquote><h3 id="_6-tool-工具调用-function-calling" tabindex="-1">6. Tool（工具调用 / Function Calling） <a class="header-anchor" href="#_6-tool-工具调用-function-calling" aria-label="Permalink to &quot;6. Tool（工具调用 / Function Calling）&quot;">​</a></h3><ul><li>让 LLM 突破&quot;只会说话&quot;的限制，能<strong>调用外部函数/API</strong> 获取实时信息或执行动作。</li><li>工作流程： <ol><li>模型根据需求决定&quot;要调哪个工具、传什么参数&quot;（输出结构化 JSON）。</li><li>宿主程序执行该工具（查天气、读数据库、发邮件……）。</li><li>把<strong>工具结果</strong>作为新一段 Context 回灌给模型。</li><li>模型基于结果继续推理/回答。</li></ol></li><li>工具本身要用<strong>某种协议</strong>暴露能力——于是有了 MCP。</li></ul><h3 id="_7-mcp-model-context-protocol-模型上下文协议" tabindex="-1">7. MCP（Model Context Protocol，模型上下文协议） <a class="header-anchor" href="#_7-mcp-model-context-protocol-模型上下文协议" aria-label="Permalink to &quot;7. MCP（Model Context Protocol，模型上下文协议）&quot;">​</a></h3><ul><li>一套<strong>开放标准协议</strong>（由 Anthropic 提出），让 LLM/客户端以统一方式与各种外部数据源、工具对接。</li><li>类比：<strong>MCP 之于 AI 工具，如同 USB-C 之于硬件接口</strong>——一套协议接百种设备。</li><li>组成： <ul><li><strong>MCP Server</strong>：把具体能力（文件系统、数据库、GitHub、浏览器……）封装成标准接口。</li><li><strong>MCP Client</strong>：集成在 Agent/IDE/应用中，连接并调用 Server。</li></ul></li><li>价值：开发者只需实现一次 MCP Server，任意兼容 MCP 的客户端都能复用，<strong>避免为每个工具写定制集成</strong>。</li></ul><h3 id="_8-agent-智能体" tabindex="-1">8. Agent（智能体） <a class="header-anchor" href="#_8-agent-智能体" aria-label="Permalink to &quot;8. Agent（智能体）&quot;">​</a></h3><ul><li>以 LLM 为&quot;大脑&quot;，<strong>自主规划 + 调用 Tool + 迭代执行</strong>来完成复杂目标的系统。</li><li>与&quot;单次问答&quot;的区别：Agent 会<strong>多步循环</strong>——思考→调工具→看结果→再思考，直到任务完成。</li><li>典型循环（ReAct 范式）：<div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Thought（思考）→ Action（选 Tool+参数）→ Observation（看结果）→ Thought → ... → Answer</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>例子：自动订机票的 Agent = LLM(规划) + 日历 Tool + 航班查询 Tool + 支付 Tool。</li></ul><h3 id="_9-agent-skill-智能体技能" tabindex="-1">9. Agent Skill（智能体技能） <a class="header-anchor" href="#_9-agent-skill-智能体技能" aria-label="Permalink to &quot;9. Agent Skill（智能体技能）&quot;">​</a></h3><ul><li>为 Agent <strong>预置的、封装好的专用能力/工作流</strong>，让它在特定领域表现得像&quot;专家&quot;。</li><li>通常包含：领域知识、标准操作步骤（SOP）、可调用的脚本/工具。</li><li>类比：Agent 是&quot;通才员工&quot;，Skill 是&quot;上岗培训手册 + 专用工具箱&quot;。</li><li>触发方式：用户意图匹配时自动加载，或显式调用。加载后 Skill 的指令会进入 Context，指导 Agent 按规范完成任务（例如&quot;代码审查技能&quot;&quot;画架构图技能&quot;）。</li></ul><hr><h2 id="三、概念串联-一次完整交互的流转" tabindex="-1">三、概念串联：一次完整交互的流转 <a class="header-anchor" href="#三、概念串联-一次完整交互的流转" aria-label="Permalink to &quot;三、概念串联：一次完整交互的流转&quot;">​</a></h2><p>以&quot;让 Agent 帮你查天气并写报告&quot;为例：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 你发出 User Prompt：&quot;明天北京天气如何？写份简短报告&quot;</span></span>
<span class="line"><span>2. Agent 读取 System Prompt（你设定的助手角色/规则）</span></span>
<span class="line"><span>3. Context = System + User Prompt 送入 LLM</span></span>
<span class="line"><span>4. LLM 判断：需要实时数据 → 选择 Weather Tool，输出调用参数</span></span>
<span class="line"><span>5. 通过 MCP 协议，MCP Client 调用 Weather MCP Server 拿到天气数据</span></span>
<span class="line"><span>6. 工具结果回灌进 Context（Observation）</span></span>
<span class="line"><span>7. LLM 基于完整 Context 生成报告（逐 Token 输出）</span></span>
<span class="line"><span>8. 若启用了&quot;报告排版 Skill&quot;，该 Skill 指令注入 Context，规范输出格式</span></span>
<span class="line"><span>9. 全程受 Context Window 限制：过长对话会压缩/截断</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>可见：<strong>LLM 是核心，Token 度量一切，Context 承载信息，Prompt 下达指令，Tool+MCP 提供手脚，Agent 做编排，Skill 给专家套路。</strong></p><hr><h2 id="四、核心概念对照表" tabindex="-1">四、核心概念对照表 <a class="header-anchor" href="#四、核心概念对照表" aria-label="Permalink to &quot;四、核心概念对照表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>概念</th><th>一句话定义</th><th>类比</th></tr></thead><tbody><tr><td>LLM</td><td>预测下一个 Token 的模型</td><td>大脑</td></tr><tr><td>Token</td><td>文本最小单位，计费/长度单位</td><td>字/词颗粒</td></tr><tr><td>Context</td><td>模型本次看到的所有文本</td><td>工作台上的资料</td></tr><tr><td>Context Window</td><td>单次最多看多少 Token</td><td>桌面大小</td></tr><tr><td>Prompt</td><td>给模型的指令</td><td>任务书</td></tr><tr><td>System Prompt</td><td>顶层角色/规则设定</td><td>员工手册</td></tr><tr><td>User Prompt</td><td>用户实际输入</td><td>具体需求</td></tr><tr><td>Tool</td><td>模型可调用的外部函数</td><td>手的延伸</td></tr><tr><td>MCP</td><td>连接工具的统一协议</td><td>USB-C 接口</td></tr><tr><td>Agent</td><td>自主规划+调工具完成任务</td><td>自动执行的员工</td></tr><tr><td>Agent Skill</td><td>预置的专用能力/工作流</td><td>专家培训包</td></tr></tbody></table><blockquote><p>记忆口诀：<strong>LLM 用 Token 思考，在 Context Window 里读 Context（含 System/User Prompt），靠 Tool 和 MCP 动手，由 Agent 编排成事，用 Skill 变专家。</strong></p></blockquote>`,38)])])}const h=t(l,[["render",o]]);export{m as __pageData,h as default};
